let aiPanelOpen = false;
let aiChatHistory = [];

function toggleAIAdvisor(){
  aiPanelOpen = !aiPanelOpen;
  const panel = document.getElementById('ai-advisor-panel');
  panel.style.display = aiPanelOpen ? 'flex' : 'none';
  if(aiPanelOpen) document.getElementById('ai-input').focus();
}

function askQuick(q){
  document.getElementById('ai-input').value = q;
  sendAIMessage();
}

async function sendAIMessage(){
  const input = document.getElementById('ai-input');
  const msg = input.value.trim();
  if(!msg) return;
  input.value = '';

  const msgs = document.getElementById('ai-chat-messages');

  // Add user message
  msgs.innerHTML += `<div class="ai-msg ai-msg--user"><div>${msg}</div></div>`;

  // Add typing indicator
  const typingId = 'typing-'+Date.now();
  msgs.innerHTML += `<div class="ai-msg ai-msg--bot" id="${typingId}"><div class="ai-typing"><span></span><span></span><span></span></div></div>`;
  msgs.scrollTop = msgs.scrollHeight;

  // Add to history
  aiChatHistory.push({role:'user', content: msg});

  // Disable send
  const btn = document.getElementById('ai-send-btn');
  btn.disabled = true; btn.style.opacity = '0.5';

  try {
    const animalsContext = ANIMALS.slice(0,6).map(a=>`${a.name} (${a.breed}, ${a.age}, ${a.location})`).join(', ');
    const systemPrompt = `You are PawAdvisor, a friendly AI assistant for PawConnect — a pet adoption and animal welfare platform. 
Help users with: pet adoption advice, which pet suits their lifestyle, pet health & vaccination questions, lost & found pet guidance, and general animal care tips.
Keep responses warm, concise (2-4 sentences max), and emoji-friendly 🐾. 
Current available pets: ${animalsContext}.
Never give medical diagnoses — always recommend a vet for health concerns.`;

    const response = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        model: 'claude-sonnet-4-20250514',
        max_tokens: 300,
        system: systemPrompt,
        messages: aiChatHistory
      })
    });

    const data = await response.json();
    const reply = data.content?.[0]?.text || "Sorry, I couldn't process that. Please try again! 🐾";

    // Add to history
    aiChatHistory.push({role:'assistant', content: reply});
    if(aiChatHistory.length > 12) aiChatHistory = aiChatHistory.slice(-12);

    // Remove typing, add reply
    document.getElementById(typingId)?.remove();
    msgs.innerHTML += `<div class="ai-msg ai-msg--bot"><div style="background:var(--sand);border-radius:16px 16px 16px 4px;padding:12px 14px;font-size:.88rem;line-height:1.55;color:var(--bark)">${reply.replace(/\n/g,'<br>')}</div></div>`;

  } catch(err) {
    document.getElementById(typingId)?.remove();
    msgs.innerHTML += `<div class="ai-msg ai-msg--bot"><div style="background:var(--sand);border-radius:16px 16px 16px 4px;padding:12px 14px;font-size:.88rem;color:var(--bark)">I'm having trouble connecting right now. Please try again in a moment! 🐾</div></div>`;
  }

  btn.disabled = false; btn.style.opacity = '1';
  msgs.scrollTop = msgs.scrollHeight;
}

