// PAGE NAVIGATION
// ══════════════════════════════════════════
function showPage(page) {
  document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));
  const el = document.getElementById('page-'+page);
  if(el) { el.classList.add('active'); currentPage=page; }
  document.querySelectorAll('.navbar__nav a').forEach(a=>{
    a.classList.toggle('active', a.dataset.page===page);
  });
  window.scrollTo(0,0);
  if(page==='adoption') renderAdoption();
  if(page==='lostfound') renderLF();
  if(page==='health') renderHealth();
  if(page==='admin') renderAdmin();
  if(page==='home') renderHomeRecent();
}

// scroll effect
window.addEventListener('scroll',()=> document.getElementById('navbar').classList.toggle('scrolled',scrollY>40));

// ══════════════════════════════════════════
// TOAST
// ══════════════════════════════════════════
function showToast(msg,type='default',ms=3000){
  const c=document.getElementById('toast-container');
  const icons={success:'✅',error:'❌',default:'🐾'};
  const t=document.createElement('div');
  t.className=`toast ${type}`;
  t.innerHTML=`<span>${icons[type]||'🐾'}</span><span>${msg}</span>`;
  c.appendChild(t);
  setTimeout(()=>{t.style.opacity='0';t.style.transform='translateX(100px)';t.style.transition='.3s';setTimeout(()=>t.remove(),300);},ms);
}

