// ══════════════════════════════════════════
// GOOGLE SIGN-IN
// ══════════════════════════════════════════
function handleGoogleCredential(response) {
  try {
    // Decode the JWT token from Google
    const base64Url = response.credential.split('.')[1];
    const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
    const profile = JSON.parse(window.atob(base64));

    const name  = profile.name  || profile.email.split('@')[0];
    const email = profile.email;
    const pic   = profile.picture || '';

    // Register or login via mock backend
    let user = MockBackend.findUser(email);
    if (!user) {
      // Auto-register Google user
      const result = MockBackend.registerUser(name, email, 'google_oauth_' + Date.now());
      user = result.user;
    } else {
      user = { id: user.id, name: user.name, email: user.email, role: user.role };
    }

    if (pic) user.photo = pic;
    currentUser = user;
    localStorage.setItem('pc_user', JSON.stringify(user));
    updateNavForUser(user);
    showToast(`Welcome, ${name.split(' ')[0]}! 🐾`, 'success', 3000);
    setTimeout(() => showPage(user.role === 'admin' ? 'admin' : 'home'), 600);

  } catch(err) {
    showToast('Google sign-in failed. Please try again.', 'error');
  }
}

function googleSignInFallback() {
  showToast('Please enable pop-ups for Google Sign-In to work.', 'default', 4000);
}

function initGoogleSignIn() {
  if (typeof google === 'undefined') {
    document.getElementById('google-signin-btn').style.display = 'none';
    document.getElementById('g-signin-fallback').style.display = 'block';
    return;
  }
  google.accounts.id.initialize({
    client_id: '1072697255812-placeholder.apps.googleusercontent.com',
    callback: handleGoogleCredential,
    auto_select: false,
    cancel_on_tap_outside: true,
  });
  google.accounts.id.renderButton(
    document.getElementById('google-signin-btn'),
    {
      theme: 'outline',
      size: 'large',
      width: '100%',
      text: 'continue_with',
      shape: 'rectangular',
      logo_alignment: 'left',
    }
  );
}

// Init Google Sign-In once the GSI script loads
window.addEventListener('load', () => {
  setTimeout(initGoogleSignIn, 500);
});
const MockBackend = {
  // User management
  getUsers(){ return JSON.parse(localStorage.getItem('pc_users')||'[]'); },
  saveUsers(u){ localStorage.setItem('pc_users',JSON.stringify(u)); },
  findUser(email){ return this.getUsers().find(u=>u.email.toLowerCase()===email.toLowerCase()); },
  registerUser(name,email,password){
    const users=this.getUsers();
    if(this.findUser(email)) return {ok:false,message:'An account with this email already exists.'};
    const user={id:Date.now(),name,email,password:btoa(password),role:email.toLowerCase().includes('admin')?'admin':'user',joined:new Date().toISOString().split('T')[0]};
    users.push(user);this.saveUsers(users);
    return {ok:true,user:{id:user.id,name:user.name,email:user.email,role:user.role}};
  },
  loginUser(email,password){
    const u=this.findUser(email);
    if(!u) return {ok:false,message:'No account found with this email. Please sign up first.'};
    if(u.password!==btoa(password)) return {ok:false,message:'Incorrect password. Please try again.'};
    return {ok:true,user:{id:u.id,name:u.name,email:u.email,role:u.role},token:'demo_token_'+u.id};
  },
  forgotPassword(email){
    const u=this.findUser(email);
    if(!u) return {ok:false,message:'No account found with this email address.'};
    // Simulate sending reset link
    return {ok:true};
  }
};

async function handleForgotPassword(){
  const emailInput=document.getElementById('forgot-email-input');
  const emailErr=document.getElementById('forgot-email-error');
  const email=emailInput.value.trim();
  const emailRegex=/^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if(!email||!emailRegex.test(email)){
    emailInput.classList.add('error');
    emailErr.classList.add('show');
    return;
  }
  emailInput.classList.remove('error');
  emailErr.classList.remove('show');
  const btn=document.getElementById('forgot-send-btn');
  btn.textContent='Sending…';btn.disabled=true;

  // Generate a mock reset token & link
  const resetToken = btoa(email + '_' + Date.now());
  const resetLink = `${window.location.href.split('?')[0]}?reset=${resetToken}`;

  // Get user name if registered
  const user = MockBackend.findUser(email);
  const toName = user ? user.name : email.split('@')[0];

  try {
    await emailjs.send('service_yyye04r', 'template_8jvc7uj', {
      email: email,
      to_name: toName,
      link: resetLink,
    });

    document.getElementById('forgot-email-display').textContent = email;
    document.getElementById('forgot-step-1').style.display = 'none';
    document.getElementById('forgot-step-2').style.display = 'block';

  } catch(err) {
    console.error('EmailJS error:', JSON.stringify(err));
    showToast(`EmailJS Error: ${err?.text || err?.message || JSON.stringify(err)}`, 'error', 8000);
  }

  btn.textContent='Send Reset Link 📧';btn.disabled=false;
}

function switchAuthTab(btn,tab){
  document.querySelectorAll('.auth-tab').forEach(t=>t.classList.remove('active'));
  btn.classList.add('active');
  document.getElementById('auth-login').classList.toggle('active',tab==='login');
  document.getElementById('auth-signup').classList.toggle('active',tab==='signup');
}
async function handleLogin(e){
  e.preventDefault();
  const email=document.getElementById('login-email').value;
  const pw=document.getElementById('login-pw').value;
  if(!email||!pw){showToast('Please fill all fields','error');return;}
  if(pw.length<6){showToast('Password must be at least 6 characters','error');return;}
  const btn=e.target.querySelector('button[type="submit"]');
  btn.textContent='Signing in…';btn.disabled=true;
  await new Promise(r=>setTimeout(r,700));
  const result = MockBackend.loginUser(email, pw);
  if(result.ok){
    const user=result.user;
    currentUser=user;localStorage.setItem('pc_user',JSON.stringify(user));
    if(result.token)localStorage.setItem('pc_token',result.token);
    updateNavForUser(user);
    showToast(`Welcome back, ${user.name.split(' ')[0]}! 🐾`,'success',3000);
    setTimeout(()=>showPage(user.role==='admin'?'admin':'home'),800);
  } else {
    showToast(result.message||'Invalid email or password','error');
  }
  btn.textContent='Sign In →';btn.disabled=false;
}
async function handleSignup(e){
  e.preventDefault();
  const name=document.getElementById('signup-name').value;
  const email=document.getElementById('signup-email').value;
  const pw=document.getElementById('signup-pw').value;
  const confirm=document.getElementById('signup-confirm').value;
  if(!name||!email||!pw){showToast('Please fill all required fields','error');return;}
  if(pw.length<8){showToast('Password must be at least 8 characters','error');return;}
  if(pw!==confirm){showToast('Passwords do not match','error');return;}
  const btn=e.target.querySelector('button[type="submit"]');
  btn.textContent='Creating account…';btn.disabled=true;
  await new Promise(r=>setTimeout(r,800));
  const result = MockBackend.registerUser(name, email, pw);
  if(result.ok){
    const user=result.user;
    currentUser=user;localStorage.setItem('pc_user',JSON.stringify(user));
    updateNavForUser(user);
    showToast(`Welcome to PawConnect, ${name.split(' ')[0]}! 🎉`,'success',3000);
    setTimeout(()=>showPage('home'),800);
  } else {
    showToast(result.message||'Registration failed','error');
  }
  btn.textContent='Create Account 🐾';btn.disabled=false;
}
function updateNavForUser(user){
  document.getElementById('nav-actions').innerHTML=user
    ?`<span style="font-size:.88rem;font-weight:500;color:var(--bark-md)">Hi, ${user.name.split(' ')[0]}!</span><button class="btn btn-secondary btn-sm" onclick="handleLogout()">Logout</button>`
    :`<a onclick="showPage('auth')" class="btn btn-secondary btn-sm">Login</a><a onclick="showPage('auth')" class="btn btn-primary btn-sm">Sign Up</a>`;
}
function handleLogout(){
  currentUser=null;localStorage.removeItem('pc_user');
  updateNavForUser(null);showToast('Logged out successfully','success');showPage('home');
}
function updateStrength(pw){
  let score=0;
  if(pw.length>=8)score++;if(/[A-Z]/.test(pw))score++;if(/[0-9]/.test(pw))score++;if(/[^A-Za-z0-9]/.test(pw))score++;
  const fills=['','fill-1','fill-2','fill-3','fill-3'];
  const labels=['','Weak','Fair','Good','Strong'];
  const colors=['','#e45c5c','var(--gold)','var(--moss)','var(--moss)'];
  for(let i=1;i<=4;i++){const s=document.getElementById('ps'+i);if(s){s.className='password-strength__seg';if(i<=score)s.classList.add(fills[score]);}}
  const lbl=document.getElementById('pw-label');if(lbl){lbl.textContent=score?labels[score]:'';lbl.style.color=colors[score];}
}

