let currentLang = 'en';

// Map translation keys to DOM elements
const LANG_MAP = [
  // Navbar
  {sel:'#main-nav a[onclick*="home"]',      key:'nav_home'},
  {sel:'#main-nav a[onclick*="adoption"]',  key:'nav_adopt'},
  {sel:'#main-nav a[onclick*="lostfound"]', key:'nav_lost'},
  {sel:'#main-nav a[onclick*="health"]',    key:'nav_health'},
  {sel:'#main-nav a[onclick*="admin"]',     key:'nav_admin'},
  // Auth tabs
  {sel:'.auth-tab:nth-child(1)',            key:'login_tab'},
  {sel:'.auth-tab:nth-child(2)',            key:'signup_tab'},
  // Login form
  {sel:'#auth-login label:nth-of-type(1)',  key:'login_email'},
  {sel:'#auth-login label:nth-of-type(2)',  key:'login_pw'},
  {sel:'#auth-login .auth-form a[onclick*="forgot"]', key:'login_forgot'},
  {sel:'#auth-login button[type="submit"]', key:'login_btn'},
  // Signup form
  {sel:'#auth-signup label:nth-of-type(1)', key:'signup_name'},
  {sel:'#auth-signup label:nth-of-type(2)', key:'signup_email'},
  {sel:'#auth-signup label:nth-of-type(3)', key:'signup_phone'},
  {sel:'#auth-signup label:nth-of-type(4)', key:'signup_pw'},
  {sel:'#auth-signup label:nth-of-type(5)', key:'signup_confirm'},
  {sel:'#auth-signup button[type="submit"]',key:'signup_btn'},
  // Forgot password modal
  {sel:'#forgot-step-1 .btn',               key:'forgot_send'},
  {sel:'#forgot-step-2 h3',                 key:'forgot_check'},
];

function setLang(lang, el){
  currentLang = lang;
  const t = TRANSLATIONS[lang];
  if(!t) return;

  // Apply via map
  LANG_MAP.forEach(({sel, key})=>{
    const nodes = document.querySelectorAll(sel);
    nodes.forEach(node=>{ if(t[key]) node.textContent = t[key]; });
  });

  // Auth welcome heading
  const authH = document.querySelector('#page-auth .auth-form-wrap h2');
  if(authH) authH.textContent = t.login_title;
  const authP = document.querySelector('#page-auth .auth-form-wrap > div > p');
  if(authP) authP.textContent = t.login_sub;

  // Forgot modal texts
  const ftitle = document.querySelector('#forgot-pw-modal .modal__title');
  if(ftitle) ftitle.textContent = t.forgot_title;
  const fsub = document.querySelector('#forgot-pw-modal .modal__body > div:first-child > div:last-child p');
  if(fsub) fsub.textContent = t.forgot_sub;
  const fback = document.querySelector('#forgot-step-1 p a');
  if(fback) fback.textContent = t.forgot_back;

  // Navbar login/signup when logged out
  const navActions = document.getElementById('nav-actions');
  if(navActions && !currentUser){
    navActions.innerHTML = `<a onclick="showPage('auth')" class="btn btn-secondary btn-sm">${t.nav_login}</a><a onclick="showPage('auth')" class="btn btn-primary btn-sm">${t.nav_signup}</a>`;
  }

  // Hero section
  const heroEyebrow = document.querySelector('.hero__eyebrow');
  if(heroEyebrow) heroEyebrow.innerHTML = `🐾 ${t.hero_eyebrow}`;
  const heroTitle = document.querySelector('.hero__title');
  if(heroTitle) heroTitle.innerHTML = `${t.hero_title1} <em>${t.hero_title2}</em>`;
  const heroDesc = document.querySelector('.hero__desc');
  if(heroDesc) heroDesc.textContent = t.hero_desc;
  const heroBtns = document.querySelectorAll('.hero__cta .btn');
  if(heroBtns[0]) heroBtns[0].textContent = t.hero_btn1;
  if(heroBtns[1]) heroBtns[1].textContent = t.hero_btn2;

  // Features section
  const featTitle = document.querySelector('.section:nth-of-type(1) h2');
  // Recent section
  const recentEyebrow = document.querySelector('#home-recent-animals')?.closest('section')?.querySelector('.eyebrow');
  const recentTitle   = document.querySelector('#home-recent-animals')?.closest('section')?.querySelector('h2');
  const recentBtn     = document.querySelector('#home-recent-animals')?.closest('section')?.querySelector('.btn-secondary');
  if(recentEyebrow) recentEyebrow.textContent = t.recent_eyebrow;
  if(recentTitle)   recentTitle.textContent   = t.recent_title;
  if(recentBtn)     recentBtn.textContent     = t.recent_btn;

  // Update active states
  document.querySelectorAll('.lang-option').forEach(o=>o.classList.remove('active'));
  if(el) el.classList.add('active');
  localStorage.setItem('pc_lang', lang);

  closeAllPanels();
  const langNames={en:'English',te:'Telugu తెలుగు',hi:'Hindi हिन्दी',ta:'Tamil தமிழ்'};
  showToast(`Language: ${langNames[lang]} 🌐`,'success',1800);
}

// ── Panel toggle helpers ───────────────────
function togglePanel(which){
  const tp = document.getElementById('theme-panel');
  const lp = document.getElementById('lang-panel');
  if(which==='theme'){
    const isOpen = tp.classList.contains('open');
    closeAllPanels();
    if(!isOpen) tp.classList.add('open');
  } else {
    const isOpen = lp.classList.contains('open');
    closeAllPanels();
    if(!isOpen) lp.classList.add('open');
  }
}
function closeAllPanels(){
  document.getElementById('theme-panel').classList.remove('open');
  document.getElementById('lang-panel').classList.remove('open');
}
document.addEventListener('click', e=>{
  if(!e.target.closest('.toolbar-btn') && !e.target.closest('.theme-panel') && !e.target.closest('.lang-panel')){
    closeAllPanels();
  }
});

// ══════════════════════════════════════════
// INIT
// ══════════════════════════════════════════
document.addEventListener('DOMContentLoaded',()=>{
  if(currentUser)updateNavForUser(currentUser);
  renderHomeRecent();

  // Restore saved theme
  const savedTheme = localStorage.getItem('pc_theme');
  if(savedTheme && savedTheme!=='default'){
    const swatchEl = document.querySelector(`.theme-swatch[data-theme="${savedTheme}"]`);
    setTheme(savedTheme, swatchEl);
  }

  // Restore saved language
  const savedLang = localStorage.getItem('pc_lang');
  if(savedLang && savedLang!=='en'){
    const langEl = document.querySelector(`.lang-option[data-lang="${savedLang}"]`);
    setLang(savedLang, langEl);
  }

  function showSection(sectionId) {
  // Hide all sections
  document.querySelectorAll("section").forEach(section => {
    section.style.display = "none";
  });

  // Show selected section
  document.getElementById(sectionId).style.display = "block";
}
});